import{_ as t,c as o,o as r,a4 as a}from"./chunks/framework.I1cCAST3.js";const s="/assets/host_bastion_create.D6980TuN.png",d="/assets/host_basion_manage.UXd4m7qH.png",u=JSON.parse('{"title":"添加堡垒机","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/add-bastion.md","filePath":"docs/hosts/add-bastion.md"}'),e={name:"docs/hosts/add-bastion.md"},n=a('<h1 id="添加堡垒机" tabindex="-1">添加堡垒机 <a class="header-anchor" href="#添加堡垒机" aria-label="Permalink to &quot;添加堡垒机&quot;">​</a></h1><p>将堡垒机添加到 Chaterm，以访问从集中式堡垒机（跳板服务器）系统同步的企业级资产。</p><div class="info custom-block"><p class="custom-block-title">什么是堡垒机？</p><p>堡垒机（也称跳板服务器）是一台加固的网关服务器，位于您的本地机器和需要管理的内部服务器之间。您无需直接连接每台服务器，而是通过堡垒机进行连接，堡垒机负责执行访问控制、审计和安全策略。企业使用堡垒机来集中管理谁可以访问哪些服务器，并维护所有会话的完整审计记录。</p></div><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>添加堡垒机之前，请确保您已准备好：</p><ul><li><strong>Chaterm 已安装</strong> 并正在运行。如果尚未安装，请参阅 <a href="/docs/start/downloads/">下载</a>。</li><li><strong>堡垒机凭据</strong> -- 通常是 SSH 密钥和密码的组合，具体取决于您组织的堡垒机系统要求。</li><li><strong>连接地址</strong> -- 堡垒机的 IP 地址或域名，以及 SSH 端口。</li><li>由组织管理员授予的通过堡垒机连接的 <strong>访问权限</strong>。</li></ul><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><p><img src="'+s+'" alt=""></p><ol><li>从左侧边栏打开 <strong>主机管理</strong> 页面。</li><li>点击主机管理页面右上角的 <strong>添加主机</strong> 按钮。</li><li>在打开的 <strong>添加主机</strong> 侧边栏中，将 <strong>设备类型</strong> 设为 <strong>服务器/堡垒机</strong>。</li><li>填写下表所述的其余配置项。</li><li>点击 <strong>创建</strong> 保存堡垒机。</li></ol><h2 id="配置项说明" tabindex="-1">配置项说明 <a class="header-anchor" href="#配置项说明" aria-label="Permalink to &quot;配置项说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>必填</th></tr></thead><tbody><tr><td><strong>设备类型</strong></td><td>选择 <strong>服务器/堡垒机</strong> 表示这是堡垒机资源。</td><td>是</td></tr><tr><td><strong>连接 IP/URL</strong></td><td>堡垒机的 IP 地址或域名（如 <code>bastion.corp.example.com</code>）。</td><td>是</td></tr><tr><td><strong>端口</strong></td><td>堡垒机上的 SSH 服务端口，默认值为 <code>22</code>。</td><td>是</td></tr><tr><td><strong>用户名</strong></td><td>堡垒机系统分配给您的 SSH 登录用户名。</td><td>是</td></tr><tr><td><strong>密钥</strong></td><td>选择堡垒机要求的 SSH 认证密钥。密钥可在 <a href="/docs/manage/keys/">密钥管理</a> 中管理。</td><td>是</td></tr><tr><td><strong>密码</strong></td><td>堡垒机要求的认证密码。某些堡垒机系统同时要求密钥和密码以实现双因素认证。</td><td>是</td></tr><tr><td><strong>SSH 代理</strong></td><td>如果堡垒机本身需要通过中间代理服务器才能访问，请在此配置代理详情。直接连接时留空。</td><td>否</td></tr><tr><td><strong>别名</strong></td><td>便于在主机列表中识别此堡垒机的显示名称（如 <code>生产堡垒机</code>）。</td><td>是</td></tr><tr><td><strong>分组</strong></td><td>将堡垒机分配到分组以便于管理（如 <code>bastion</code>、<code>production</code>）。可选择现有分组或输入新名称。</td><td>否</td></tr></tbody></table><h2 id="同步堡垒机资产" tabindex="-1">同步堡垒机资产 <a class="header-anchor" href="#同步堡垒机资产" aria-label="Permalink to &quot;同步堡垒机资产&quot;">​</a></h2><p><img src="'+d+'" alt=""></p><p>添加堡垒机后，Chaterm 会在堡垒机资源页面显示它以及通过它可访问的内部资产列表。</p><p>要使用堡垒机系统的最新信息更新资产列表：</p><ol><li>在工作区中导航到 <strong>堡垒机资源</strong> 标签。</li><li>找到您要刷新的堡垒机条目。</li><li>点击堡垒机旁边的 <strong>刷新</strong> 按钮以手动同步最新资产数据。</li></ol><p>同步完成后，内部资产将像个人主机一样显示在列表中。点击任意资产即可建立 SSH 连接。您也可以右键点击资产将其添加到收藏夹、添加备注或分配到自定义分组。</p><h2 id="自定义分组管理" tabindex="-1">自定义分组管理 <a class="header-anchor" href="#自定义分组管理" aria-label="Permalink to &quot;自定义分组管理&quot;">​</a></h2><p>您可以创建自定义分组，以适合您团队的方式组织堡垒机资产：</p><ol><li>在工作区中，选择 <strong>堡垒机资源</strong> 标签。</li><li>点击右上角的 <strong>自定义分组</strong> 按钮。</li><li>填写分组详情： <ul><li><strong>分组名称</strong> -- 简短的描述性名称（如 <code>Web 服务器</code>、<code>数据库层</code>）。</li><li><strong>分组描述</strong> -- 可选的备注，说明该分组包含的内容。</li></ul></li><li>点击 <strong>保存</strong> 创建分组。</li></ol><p>要编辑或删除现有自定义分组，在堡垒机资源页面右键点击该分组，从右键菜单中选择相应操作。</p><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/docs/manage/keys/">密钥管理</a> -- 导入和管理用于堡垒机认证的 SSH 密钥。</li><li><a href="/docs/hosts/connect">连接到主机</a> -- 了解连接到堡垒机资产时可用的终端功能。</li><li><a href="/docs/hosts/edit-clone-delete">编辑、克隆与删除</a> -- 修改或删除堡垒机条目。</li></ul>',23),l=[n];function i(c,h,g,p,_,m){return r(),o("div",null,l)}const f=t(e,[["render",i]]);export{u as __pageData,f as default};
